from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    allowed_edges = []
    for u, v, cost in edges:
        if online[u] and online[v]:
            allowed_edges.append((u, v, cost))
    if not allowed_edges:
        return -1

    original_adj = [[] for _ in range(n)]
    original_in_degree = [0] * n
    for u, v, _ in edges:
        original_adj[u].append(v)
        original_in_degree[v] += 1

    q = deque()
    for i in range(n):
        if original_in_degree[i] == 0:
            q.append(i)
    topo_order = []
    while q:
        u = q.popleft()
        topo_order.append(u)
        for v in original_adj[u]:
            original_in_degree[v] -= 1
            if original_in_degree[v] == 0:
                q.append(v)

    max_edge = max(cost for u, v, cost in allowed_edges)
    low, high = 0, max_edge
    answer = -1

    while low <= high:
        mid = (low + high) // 2
        adj = [[] for _ in range(n)]
        for u, v, cost in allowed_edges:
            if cost >= mid:
                adj[u].append((v, cost))

        min_cost = [float('inf')] * n
        min_cost[0] = 0
        for u in topo_order:
            if min_cost[u] == float('inf'):
                continue
            for v, cost in adj[u]:
                if min_cost[v] > min_cost[u] + cost:
                    min_cost[v] = min_cost[u] + cost

        if min_cost[-1] <= k:
            answer = mid
            low = mid + 1
        else:
            high = mid - 1

    return answer if answer != -1 else -1
